from __future__ import annotations

import argparse
import difflib
import os
import shutil
import subprocess
import sys
import tempfile
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, Optional


@dataclass
class RunResult:
    returncode: int
    stdout: str
    stderr: str


def run(cmd: list[str], cwd: Optional[Path] = None, env: Optional[dict[str, str]] = None) -> RunResult:
    p = subprocess.run(
        cmd,
        cwd=str(cwd) if cwd else None,
        env=env,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
    )
    return RunResult(p.returncode, p.stdout, p.stderr)


def die(msg: str, code: int = 2) -> None:
    sys.stderr.write(msg.rstrip() + "\n")
    raise SystemExit(code)


def ensure_file(path: Path, what: str) -> None:
    if not path.exists():
        die(f"{what} not found: {path}")


def which_or_die(exe: str) -> str:
    p = shutil.which(exe)
    if not p:
        die(f"Required executable not found on PATH: {exe}")
    return p


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def unified_diff(a: str, b: str, fromfile: str, tofile: str) -> str:
    return "".join(
        difflib.unified_diff(
            a.splitlines(keepends=True),
            b.splitlines(keepends=True),
            fromfile=fromfile,
            tofile=tofile,
        )
    )


def pip_compile(
    in_file: Path,
    out_file: Path,
    upgrade: bool,
    upgrade_package: Optional[list[str]],
    generate_hashes: bool,
    allow_unsafe: bool,
    resolver: Optional[str],
    extra_args: list[str],
) -> None:
    ensure_file(in_file, "Input requirements file")
    cmd = [sys.executable, "-m", "piptools", "compile", str(in_file), "--output-file", str(out_file)]
    if upgrade:
        cmd.append("--upgrade")
    if upgrade_package:
        for pkg in upgrade_package:
            cmd += ["--upgrade-package", pkg]
    if generate_hashes:
        cmd.append("--generate-hashes")
    if allow_unsafe:
        cmd.append("--allow-unsafe")
    if resolver:
        cmd += ["--resolver", resolver]
    cmd += extra_args

    r = run(cmd)
    if r.returncode != 0:
        sys.stderr.write(r.stdout)
        sys.stderr.write(r.stderr)
        die("pip-compile failed", r.returncode)
    sys.stdout.write(r.stdout)
    sys.stderr.write(r.stderr)


def pip_verify(
    in_file: Path,
    out_file: Path,
    generate_hashes: bool,
    allow_unsafe: bool,
    resolver: Optional[str],
    extra_args: list[str],
) -> None:
    ensure_file(in_file, "Input requirements file")
    ensure_file(out_file, "Lock requirements file")

    with tempfile.TemporaryDirectory() as td:
        tmp_out = Path(td) / "requirements.txt"
        cmd = [sys.executable, "-m", "piptools", "compile", str(in_file), "--output-file", str(tmp_out)]
        if generate_hashes:
            cmd.append("--generate-hashes")
        if allow_unsafe:
            cmd.append("--allow-unsafe")
        if resolver:
            cmd += ["--resolver", resolver]
        cmd += extra_args

        r = run(cmd)
        if r.returncode != 0:
            sys.stderr.write(r.stdout)
            sys.stderr.write(r.stderr)
            die("pip-compile (verify) failed", r.returncode)

        expected = read_text(out_file)
        actual = read_text(tmp_out)
        if expected != actual:
            diff = unified_diff(expected, actual, fromfile=str(out_file), tofile=str(out_file) + " (recompiled)")
            sys.stderr.write(diff)
            die(f"Lock file out of date: {out_file}", 1)

    sys.stdout.write(f"OK: {out_file} is up to date with {in_file}\n")


def poetry_lock(no_update: bool) -> None:
    which_or_die("poetry")
    cmd = ["poetry", "lock"]
    if no_update:
        cmd.append("--no-update")
    r = run(cmd)
    sys.stdout.write(r.stdout)
    sys.stderr.write(r.stderr)
    if r.returncode != 0:
        die("poetry lock failed", r.returncode)


def poetry_update(package: Optional[str]) -> None:
    which_or_die("poetry")
    cmd = ["poetry", "update"]
    if package:
        cmd.append(package)
    r = run(cmd)
    sys.stdout.write(r.stdout)
    sys.stderr.write(r.stderr)
    if r.returncode != 0:
        die("poetry update failed", r.returncode)


def poetry_verify() -> None:
    which_or_die("poetry")
    cmd = ["poetry", "lock", "--check"]
    r = run(cmd)
    sys.stdout.write(r.stdout)
    sys.stderr.write(r.stderr)
    if r.returncode != 0:
        die("poetry lock check failed (lock out of date or invalid)", 1)
    sys.stdout.write("OK: poetry.lock is consistent with pyproject.toml\n")


def poetry_export(out_file: Path, with_hashes: bool, groups: Optional[list[str]], without_groups: Optional[list[str]]) -> None:
    which_or_die("poetry")
    cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(out_file)]
    if with_hashes:
        cmd.append("--with-hashes")
    if groups:
        for g in groups:
            cmd += ["--only", g]
    if without_groups:
        for g in without_groups:
            cmd += ["--without", g]
    r = run(cmd)
    sys.stdout.write(r.stdout)
    sys.stderr.write(r.stderr)
    if r.returncode != 0:
        die("poetry export failed (ensure poetry-plugin-export is installed if needed)", r.returncode)


def poetry_export_with_hashes_via_piptools(out_file: Path, groups: Optional[list[str]], without_groups: Optional[list[str]]) -> None:
    which_or_die("poetry")
    with tempfile.TemporaryDirectory() as td:
        td_path = Path(td)
        exported = td_path / "exported.txt"
        poetry_export(exported, with_hashes=False, groups=groups, without_groups=without_groups)
        cmd = [
            sys.executable,
            "-m",
            "piptools",
            "compile",
            str(exported),
            "--output-file",
            str(out_file),
            "--generate-hashes",
            "--allow-unsafe",
        ]
        r = run(cmd)
        sys.stdout.write(r.stdout)
        sys.stderr.write(r.stderr)
        if r.returncode != 0:
            die("pip-compile failed while generating hashes from poetry export", r.returncode)


