    parser = argparse.ArgumentParser(
        prog="dep_lock.py",
        description="Manage Python dependency lock files (pip-tools requirements.txt with hashes or Poetry lock files).",
    )
    sub = parser.add_subparsers(dest="cmd", required=True)

    p_pc = sub.add_parser("pip-compile", help="Generate/update a pip-tools lock file (requirements.txt).")
    p_pc.add_argument("--in", dest="in_file", default="requirements.in", type=Path)
